    private fun Address.isIncomplete() = hostname.isNullOrBlank()

    private fun Address.isNonAsciiAddress() = !CharsetUtil.isASCII(address)

    /**
     * mime4j uses RFC 5322 parsing rules which allow characters in the domain part that are not valid in RFC 5321.
     * This is relevant for SMTP envelope validation (e.g. `user@gmail.com/`).
     */
    private fun Address.hasValidRfc5321Domain(): Boolean {
        val domain = hostname ?: return false

        // Allow address literals (e.g. user@[192.0.2.1])
        if (domain.startsWith("[") && domain.endsWith("]") && domain.length > 2) {
            return true
        }

        if (domain.length > 255) return false

        val labels = domain.split('.')
        if (labels.any { it.isEmpty() }) return false

        for (label in labels) {
            if (label.length !in 1..63) return false
            if (!label.first().isLetterOrDigit()) return false
            if (!label.last().isLetterOrDigit()) return false
            if (!label.all { it.isLetterOrDigit() || it == '-' }) return false
        }

        return true
    }
